What does this program print?

```cpp
#include <iostream>
#include <initializer_list>

class NumList {
    int data_[8]{};
    int count_{0};
public:
    NumList(std::initializer_list<int> list) {
        for (int v : list)
            data_[count_++] = v;
    }
    int size() const { return count_; }
    int get(int i) const { return data_[i]; }
};

int main() {
    NumList a{10, 20, 30};
    std::cout << a.size() << "\n";
    std::cout << a.get(1) << "\n";
}
```

